import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import API from '../services/axios';

function Register() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match!'); return;
    }
    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters.'); return;
    }
    setLoading(true);
    try {
      const res = await API.post('/auth/signup', {
        name: formData.name, email: formData.email, password: formData.password
      });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      navigate('/home');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Try again.');
    } finally { setLoading(false); }
  };

  const inputStyle = {
    width: '100%', padding: '13px 14px 13px 44px',
    background: 'rgba(255,255,255,0.07)', border: '1.5px solid rgba(255,255,255,0.1)',
    borderRadius: '12px', color: 'white', fontSize: '0.9rem', outline: 'none',
    boxSizing: 'border-box', transition: 'border-color 0.2s'
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0f0c29 0%, #1e1b4b 40%, #312e81 70%, #4c1d95 100%)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      padding: '2rem', position: 'relative', overflow: 'hidden', fontFamily: "'Outfit', sans-serif"
    }}>
      {/* Background orbs */}
      <div style={{ position: 'absolute', top: '-150px', left: '-100px', width: '450px', height: '450px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(124,58,237,0.2) 0%, transparent 70%)', pointerEvents: 'none' }} />
      <div style={{ position: 'absolute', bottom: '-100px', right: '-150px', width: '400px', height: '400px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(167,139,250,0.15) 0%, transparent 70%)', pointerEvents: 'none' }} />

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0', maxWidth: '900px', width: '100%', borderRadius: '24px', overflow: 'hidden', boxShadow: '0 30px 80px rgba(0,0,0,0.5)', border: '1px solid rgba(255,255,255,0.1)' }}>

        {/* Left - Form */}
        <div style={{ background: 'rgba(15,12,41,0.95)', backdropFilter: 'blur(20px)', padding: '3rem 2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>

          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '2rem' }}>
            <div style={{ width: '38px', height: '38px', background: 'linear-gradient(135deg, #7c3aed, #a78bfa)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: '800', color: 'white', fontSize: '1.1rem' }}>E</div>
            <span style={{ color: 'white', fontWeight: '700', fontSize: '1.2rem' }}>Event<span style={{ color: '#a78bfa' }}>Ease</span></span>
          </div>

          <h1 style={{ color: 'white', fontSize: '1.8rem', fontWeight: '800', marginBottom: '0.4rem' }}>Create Account</h1>
          <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.85rem', marginBottom: '1.8rem' }}>Join thousands of event lovers today</p>

          {error && (
            <div style={{ background: 'rgba(239,68,68,0.15)', border: '1px solid rgba(239,68,68,0.3)', color: '#fca5a5', padding: '12px 16px', borderRadius: '12px', marginBottom: '1.5rem', fontSize: '0.85rem' }}>
              ⚠️ {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            {/* Name */}
            <div style={{ marginBottom: '1rem' }}>
              <label style={{ display: 'block', color: 'rgba(255,255,255,0.6)', fontSize: '0.75rem', fontWeight: '600', marginBottom: '7px', letterSpacing: '0.5px' }}>FULL NAME</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)' }}>👤</span>
                <input type="text" name="name" value={formData.name} onChange={handleChange} required
                  placeholder="Your full name" style={inputStyle}
                  onFocus={e => e.target.style.borderColor = '#7c3aed'}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'} />
              </div>
            </div>

            {/* Email */}
            <div style={{ marginBottom: '1rem' }}>
              <label style={{ display: 'block', color: 'rgba(255,255,255,0.6)', fontSize: '0.75rem', fontWeight: '600', marginBottom: '7px', letterSpacing: '0.5px' }}>EMAIL ADDRESS</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)' }}>📧</span>
                <input type="email" name="email" value={formData.email} onChange={handleChange} required
                  placeholder="you@example.com" style={inputStyle}
                  onFocus={e => e.target.style.borderColor = '#7c3aed'}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'} />
              </div>
            </div>

            {/* Password */}
            <div style={{ marginBottom: '1rem' }}>
              <label style={{ display: 'block', color: 'rgba(255,255,255,0.6)', fontSize: '0.75rem', fontWeight: '600', marginBottom: '7px', letterSpacing: '0.5px' }}>PASSWORD</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)' }}>🔒</span>
                <input type="password" name="password" value={formData.password} onChange={handleChange} required
                  placeholder="Min 6 characters" style={inputStyle}
                  onFocus={e => e.target.style.borderColor = '#7c3aed'}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'} />
              </div>
            </div>

            {/* Confirm Password */}
            <div style={{ marginBottom: '1.5rem' }}>
              <label style={{ display: 'block', color: 'rgba(255,255,255,0.6)', fontSize: '0.75rem', fontWeight: '600', marginBottom: '7px', letterSpacing: '0.5px' }}>CONFIRM PASSWORD</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)' }}>✅</span>
                <input type="password" name="confirmPassword" value={formData.confirmPassword} onChange={handleChange} required
                  placeholder="Repeat your password" style={inputStyle}
                  onFocus={e => e.target.style.borderColor = '#7c3aed'}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'} />
              </div>
            </div>

            <button type="submit" disabled={loading} style={{
              width: '100%', padding: '14px',
              background: loading ? 'rgba(124,58,237,0.5)' : 'linear-gradient(135deg, #7c3aed, #a78bfa)',
              color: 'white', border: 'none', borderRadius: '12px',
              fontWeight: '700', fontSize: '0.95rem', cursor: loading ? 'not-allowed' : 'pointer',
              boxShadow: loading ? 'none' : '0 8px 25px rgba(124,58,237,0.4)', letterSpacing: '0.5px'
            }}>
              {loading ? '⏳ Creating Account...' : '🎉 Create Account'}
            </button>
          </form>

          <div style={{ marginTop: '1.5rem', textAlign: 'center' }}>
            <span style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.85rem' }}>Already have an account? </span>
            <Link to="/login" style={{ color: '#a78bfa', fontWeight: '700', fontSize: '0.85rem', textDecoration: 'none' }}>
              Sign In →
            </Link>
          </div>
        </div>

        {/* Right Panel */}
        <div style={{
          background: 'linear-gradient(135deg, #7c3aed 0%, #4c1d95 100%)',
          padding: '3rem 2.5rem', display: 'flex', flexDirection: 'column',
          justifyContent: 'center', position: 'relative', overflow: 'hidden'
        }}>
          <div style={{ position: 'absolute', top: '-60px', left: '-60px', width: '200px', height: '200px', borderRadius: '50%', background: 'rgba(255,255,255,0.08)' }} />
          <div style={{ position: 'absolute', bottom: '-40px', right: '-40px', width: '150px', height: '150px', borderRadius: '50%', background: 'rgba(255,255,255,0.05)' }} />

          <div style={{ position: 'relative' }}>
            <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🚀</div>
            <h2 style={{ color: 'white', fontSize: '2rem', fontWeight: '800', marginBottom: '1rem', lineHeight: '1.2' }}>
              Join the EventEase Community!
            </h2>
            <p style={{ color: 'rgba(255,255,255,0.7)', lineHeight: '1.7', marginBottom: '2rem', fontSize: '0.9rem' }}>
              Create your free account and start exploring thousands of amazing events happening around you.
            </p>

            {[
              { icon: '🆓', text: 'Free to join, no credit card needed' },
              { icon: '🔔', text: 'Get notified about new events' },
              { icon: '🎟️', text: 'Book tickets in seconds' },
              { icon: '⭐', text: 'Exclusive member-only deals' },
            ].map((f, i) => (
              <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '14px' }}>
                <div style={{ width: '36px', height: '36px', background: 'rgba(255,255,255,0.15)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1rem', flexShrink: 0 }}>{f.icon}</div>
                <span style={{ color: 'rgba(255,255,255,0.85)', fontSize: '0.85rem', fontWeight: '500' }}>{f.text}</span>
              </div>
            ))}

            {/* Stats */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginTop: '2rem' }}>
              {[{ num: '10K+', label: 'Users' }, { num: '500+', label: 'Events' }, { num: '50K+', label: 'Tickets Sold' }, { num: '4.9★', label: 'Rating' }].map((s, i) => (
                <div key={i} style={{ background: 'rgba(255,255,255,0.1)', borderRadius: '12px', padding: '1rem', textAlign: 'center' }}>
                  <p style={{ color: 'white', fontWeight: '800', fontSize: '1.3rem', marginBottom: '2px' }}>{s.num}</p>
                  <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.75rem' }}>{s.label}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Register;
